                    background: 'linear-gradient(to top, rgba(10,10,15,0.95) 0%, rgba(10,10,15,0.2) 60%)',
                  }}
                />
                <div
                  style={{
                    position: 'absolute',
                    bottom: 0,
                    left: 0,
                    right: 0,
                    padding: '32px',
                  }}
                >
                  <h3
                    style={{
                      fontSize: '20px',
                      fontWeight: 700,
                      margin: '0 0 8px 0',
                      color: '#ffffff',
                      textShadow: '0 2px 4px rgba(0,0,0,0.5)',
                    }}
                  >
                    {feature.title}
                  </h3>
                  <p
                    style={{
                      fontSize: '14px',
                      color: 'rgba(255,255,255,0.9)',
                      margin: 0,
                      lineHeight: 1.6,
                      textShadow: '0 1px 2px rgba(0,0,0,0.3)',
                    }}
                  >
                    {feature.description}
                  </p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ===== CLASS SHOWCASE SECTION ===== */}
      <ClassShowcase classes={SHOWCASE_CLASSES} />

      {/* ===== NEWS SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: 'transparent',
        }}
      >
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          {/* Section Header */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              marginBottom: '48px',
            }}
          >
            <h2
              style={{
                fontSize: 'clamp(24px, 3vw, 40px)',
                fontWeight: 700,
                letterSpacing: '0.05em',
                color: '#ffffff',
                textShadow: '0 2px 10px rgba(0,0,0,0.3)',
                margin: 0,
              }}
            >
              LATEST NEWS
            </h2>
            <Link
              href="/news"
              style={{
                fontSize: '14px',
                color: 'rgba(255,255,255,0.8)',
                textDecoration: 'none',
                transition: 'color 0.3s ease',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.color = '#00d4ff'; }}
              onMouseLeave={(e) => { e.currentTarget.style.color = 'rgba(255,255,255,0.8)'; }}
            >
              View All →
            </Link>
          </div>

          {/* News Items */}
          <div style={{ display: 'flex', flexDirection: 'column' }}>
            {[
              {
                date: 'Dec 15, 2024',
                category: 'Update',
                title: 'Season 4: Twilight Dominion launches with new territory wars',
              },
              {
                date: 'Dec 12, 2024',
                category: 'Event',
                title: 'Winter Solstice Festival brings exclusive mounts and cosmetics',
              },
              {
                date: 'Dec 8, 2024',
                category: 'Balance',
                title: 'Class rebalancing patch addresses Wizard burst damage concerns',
              },
            ].map((news, index) => (
              <div
                key={index}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: '20px',
                  padding: '20px 0',
                  borderBottom: index < 2 ? '1px solid #E0E0E0' : 'none',
                  cursor: 'pointer',
                  transition: 'all 0.3s ease',
                }}
                onMouseEnter={(e) => {
                  const title = e.currentTarget.querySelector('span[data-title]') as HTMLElement;
                  if (title) title.style.color = '#00d4ff';
                }}
                onMouseLeave={(e) => {
                  const title = e.currentTarget.querySelector('span[data-title]') as HTMLElement;
                  if (title) title.style.color = '#ffffff';
                }}
              >
                <span
                  style={{
                    fontSize: '13px',
                    color: '#555555',
                    whiteSpace: 'nowrap',
                    minWidth: '100px',
                  }}
                >
                  {news.date}
                </span>
                <span
                  style={{
                    fontSize: '10px',
                    fontWeight: 600,
                    letterSpacing: '0.1em',
                    textTransform: 'uppercase',
                    padding: '4px 10px',
                    background: 'rgba(0, 212, 255, 0.1)',
                    color: '#00d4ff',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {news.category}
                </span>
                <span
                  data-title="true"
                  style={{
                    fontSize: '15px',
                    color: '#111111',
                    transition: 'color 0.3s ease',
                  }}
                >
                  {news.title}
                </span>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* ===== RANKINGS PREVIEW SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: 'transparent',
        }}
      >
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          {/* Section Header */}
          <div
            style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              marginBottom: '48px',
              flexWrap: 'wrap',
              gap: '16px',
            }}
          >
            <h2
              style={{
                fontSize: 'clamp(24px, 3vw, 40px)',
                fontWeight: 700,
                letterSpacing: '0.05em',
                color: '#ffffff',
                margin: 0,
              }}
            >
              TOP PLAYERS
            </h2>
            <Link
              href="/rankings"
              style={{
                fontSize: '14px',
                color: '#7a7a8a',
                textDecoration: 'none',
                transition: 'color 0.3s ease',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.color = '#00d4ff'; }}
              onMouseLeave={(e) => { e.currentTarget.style.color = 'rgba(255,255,255,0.8)'; }}
            >
              View All Rankings →
            </Link>
          </div>

          {/* Rankings Preview */}
          <RankingsPreview
            category="players"
            entries={[
              { rank: 1, name: 'ShadowReaper', score: 98750, guild: 'Eclipse Order' },
              { rank: 2, name: 'CelestialBlade', score: 95200, guild: 'Heavenly Sword' },
              { rank: 3, name: 'VoidWalker', score: 93100, guild: 'Eclipse Order' },
              { rank: 4, name: 'PhoenixRise', score: 89400, guild: 'Crimson Wings' },
              { rank: 5, name: 'IronFist', score: 87650, guild: null },
              { rank: 6, name: 'MysticSage', score: 85300, guild: 'Arcane Circle' },
              { rank: 7, name: 'StormCaller', score: 83900, guild: 'Heavenly Sword' },
              { rank: 8, name: 'NightHunter', score: 81200, guild: null },
              { rank: 9, name: 'DragonSlayer', score: 79800, guild: 'Crimson Wings' },
              { rank: 10, name: 'FrostQueen', score: 78100, guild: 'Arcane Circle' },
            ]}
            scoreLabel="Level Score"
          />
        </div>
      </section>

      {/* ===== NEWS PREVIEW SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: 'transparent',
        }}
      >
        <div style={{ maxWidth: '1200px', margin: '0 auto' }}>
          {/* Section Header */}
          <h2
            style={{
              textAlign: 'center',
              fontSize: 'clamp(24px, 3vw, 40px)',
              fontWeight: 700,
              letterSpacing: '0.05em',
              marginBottom: '48px',
              color: '#ffffff',
            }}
          >
            LATEST NEWS
          </h2>

          {/* News Preview */}
          <NewsPreview
            articles={[
              {
                id: 1,
                title: 'Version 2.5 Patch Notes: The Celestial Awakening',
                excerpt:
                  'Major balance changes to all classes, new Celestial skill trees, and performance improvements across all territories. Venomancers receive a complete pet AI overhaul.',
                date: '2024-12-15',
                category: 'Patch Notes',
                featured: true,
              },
              {
                id: 2,
                title: 'Winter Solstice Festival Returns with New Rewards',
                excerpt:
                  'The annual Winter Solstice event brings exclusive mounts, fashion sets, and a limited-time dungeon. Earn Frost Tokens to unlock legendary gear.',
                date: '2024-12-12',
                category: 'Events',
              },
              {
                id: 3,
                title: 'Community Spotlight: Top Guild Strategies for Territory War',
                excerpt:
                  'We interviewed leaders from the top 5 guilds to learn their winning strategies for Territory War domination. Learn formation tactics and class compositions.',
                date: '2024-12-10',
                category: 'Community',
              },
              {
                id: 4,
                title: 'Scheduled Maintenance: December 18th',
                excerpt:
                  'Servers will undergo maintenance on December 18th from 02:00 to 06:00 UTC. Expect downtime for database migration and security updates.',
                date: '2024-12-08',
                category: 'Announcements',
              },
              {
                id: 5,
                title: 'Hotfix 2.4.3: Critical Bug Fixes',
                excerpt:
                  'Resolved an issue causing disconnections during Nation War. Fixed item duplication exploit and corrected Blademaster skill damage calculations.',
                date: '2024-12-05',
                category: 'Patch Notes',
              },
              {
                id: 6,
                title: 'Fan Art Contest Winners Announced',
                excerpt:
                  'Over 500 submissions were received for our annual fan art contest. Check out the stunning winning entries and honorable mentions from our talented community.',
                date: '2024-12-03',
                category: 'Community',
              },
            ]}
          />
        </div>
      </section>

      {/* ===== CTA SECTION ===== */}
      <section
        style={{
          padding: 'clamp(80px, 10vw, 128px) 24px',
          background: 'rgba(255, 255, 255, 0.1)',
          backdropFilter: 'blur(10px)',
          textAlign: 'center',
        }}
      >
        <div
          style={{
            maxWidth: '600px',
            margin: '0 auto',
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            gap: '32px',
          }}
        >
          <h2
            style={{
              fontSize: 'clamp(24px, 3vw, 36px)',
              fontWeight: 600,
              color: '#111111',
              margin: 0,
            }}
          >
            Ready to begin?
          </h2>
          <Link
            href="/register"
            style={{
              display: 'inline-block',
              padding: '16px 48px',
              background: 'rgba(0, 212, 255, 0.9)',
              color: '#ffffff',
              fontSize: '14px',
              fontWeight: 700,
              letterSpacing: '0.1em',
              textTransform: 'uppercase',
              textDecoration: 'none',
              transition: 'all 0.3s ease',
            }}
            onMouseEnter={(e) => {
              e.currentTarget.style.background = 'rgba(0, 212, 255, 1)';
              e.currentTarget.style.transform = 'translateY(-2px)';
              e.currentTarget.style.boxShadow = '0 8px 32px rgba(0, 212, 255, 0.3)';
            }}
            onMouseLeave={(e) => {
              e.currentTarget.style.background = 'rgba(0, 212, 255, 0.9)';
              e.currentTarget.style.transform = 'translateY(0)';
              e.currentTarget.style.boxShadow = 'none';
            }}
          >
            Create Free Account
          </Link>
        </div>
      </section>

      {/* ===== FOOTER ===== */}
      <footer
        style={{
          padding: '48px 24px',
          borderTop: '1px solid rgba(255, 255, 255, 0.2)',
          background: 'rgba(255, 255, 255, 0.1)',
          backdropFilter: 'blur(10px)',
        }}
      >
        <div
          style={{
            maxWidth: '1200px',
            margin: '0 auto',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'space-between',
            flexWrap: 'wrap',
            gap: '16px',
          }}
        >
          <span style={{ fontSize: '13px', color: 'rgba(255,255,255,0.8)' }}>
            © 2024 Perfect World. All rights reserved.
          </span>
          <div style={{ display: 'flex', gap: '24px' }}>
            {['Terms', 'Privacy', 'Support'].map((item) => (
              <Link
                key={item}
                href={`/${item.toLowerCase()}`}
                style={{
                  fontSize: '13px',
                  color: 'rgba(255,255,255,0.8)',
                  textDecoration: 'none',
                  transition: 'color 0.3s ease',
                }}
                onMouseEnter={(e) => { e.currentTarget.style.color = '#00d4ff'; }}
                onMouseLeave={(e) => { e.currentTarget.style.color = 'rgba(255,255,255,0.8)'; }}
              >
                {item}
              </Link>
            ))}
          </div>
        </div>
      </footer>

      {/* ===== GLOBAL KEYFRAME ANIMATION ===== */}
      <style jsx global>{`
        @keyframes borderPulse {
          0%, 100% { border-color: rgba(0, 212, 255, 0.3); }
          50% { border-color: rgba(0, 212, 255, 0.6); }
        }
        html {
          scroll-behavior: smooth;
        }
        * {
          box-sizing: border-box;
        }
        body {
          margin: 0;
          padding: 0;
        }
      `}</style>
    </main>
  );
}

</content>
